### File 3: `/Users/marc/conductor/workspaces/rudel/wellington/apps/api/src/auth.ts`

**Full contents (40 lines):**

```typescript
import * as schema from "@rudel/sql-schema";
import { betterAuth } from "better-auth";
import { drizzleAdapter } from "better-auth/adapters/drizzle";
import { bearer } from "better-auth/plugins";

export interface AuthConfig {
	appURL: string;
	secret?: string;
	socialProviders?: Record<string, { clientId: string; clientSecret: string }>;
	trustedOrigins?: string[];
}

export function createAuth(db: object, config: AuthConfig) {
	const trustedOrigins = config.trustedOrigins ?? [];
	if (!trustedOrigins.includes(config.appURL)) {
		trustedOrigins.push(config.appURL);
	}

	return betterAuth({
		baseURL: config.appURL,
		secret: config.secret,
		database: drizzleAdapter(db as Parameters<typeof drizzleAdapter>[0], {
			provider: "pg",
			schema,
		}),
		emailAndPassword: {
			enabled: true,
		},
		socialProviders: config.socialProviders,
		plugins: [bearer()],
		session: {
			expiresIn: 60 * 60 * 24 * 365,
		},
		trustedOrigins,
	});
}

export type Auth = ReturnType<typeof createAuth>;
export type Session = Auth["$Infer"]["Session"];
```

**Details:**

- Line 1: Imports `* as schema` from `@rudel/sql-schema`. This means the `schema` object passed to `drizzleAdapter` contains `{ user, session, account, verification }` -- all four table definitions.
- Line 6-11: Defines `AuthConfig` interface with `appURL` (required), `secret` (optional), `socialProviders` (optional, generic Record), and `trustedOrigins` (optional string array).
- Line 14: `createAuth` is a factory function that takes a `db` object (typed as `object` to avoid type incompatibilities with drizzle adapter) and an `AuthConfig`.
- Lines 15-17: If `trustedOrigins` is not provided, defaults to an empty array. The `appURL` is always added to `trustedOrigins` if not already present.
- Line 20: Calls `betterAuth()` with the following configuration:
  - `baseURL`: set to `config.appURL` (line 21).
  - `secret`: set to `config.secret` (line 22).
  - `database`: uses `drizzleAdapter` with `provider: "pg"` and the full schema namespace (line 23-26). The `db` parameter is cast via `as Parameters<typeof drizzleAdapter>[0]`.
  - `emailAndPassword`: enabled (lines 27-29).
  - `socialProviders`: passed through from config (line 30).
  - `plugins`: only the `bearer()` plugin (line 31). This enables Bearer token authentication (used by the CLI).
  - `session.expiresIn`: set to `60 * 60 * 24 * 365` = 31,536,000 seconds = 365 days (lines 32-34).
  - `trustedOrigins`: the computed array (line 35).
- Line 39: `Auth` is the return type of `createAuth`.
- Line 40: `Session` is extracted from `Auth["$Infer"]["Session"]`, which gives the inferred session type from `better-auth`. This type has `user` and `session` sub-properties.

