        => Promise<boolean | void | { data: Partial<User & Record<string, any>> }>;
      after?: (user: User & Record<string, unknown>, context?: GenericEndpointContext)
        => Promise<void>;
    };
  };
  session?: { create?: { before?; after? }; update?: { before?; after? } };
  account?: { create?: { before?; after? }; update?: { before?; after? } };
  verification?: { create?: { before?; after? }; update?: { before?; after? } };
};
```

#### B. Organization plugin's own `organizationHooks` (on the plugin config)

These hooks are specific to organization lifecycle events and fire during organization CRUD operations -- they do NOT fire on user signup. They are useful for reacting to org creation/deletion/update, member changes, invitation flow, and team operations.

Key hooks (from the type definitions at lines 361-753 of the `.d.ts`):

```typescript
organization({
  organizationHooks: {
    // Organization lifecycle
    beforeCreateOrganization: async (data) => { /* data.organization, data.user */ },
    afterCreateOrganization:  async (data) => { /* data.organization, data.member, data.user */ },
    beforeUpdateOrganization: async (data) => { /* data.organization, data.user, data.member */ },
    afterUpdateOrganization:  async (data) => { /* data.organization, data.user, data.member */ },
    beforeDeleteOrganization: async (data) => { /* data.organization, data.user */ },
    afterDeleteOrganization:  async (data) => { /* data.organization, data.user */ },

    // Member lifecycle
    beforeAddMember:        async (data) => { /* data.member, data.user, data.organization */ },
    afterAddMember:         async (data) => { /* data.member, data.user, data.organization */ },
    beforeRemoveMember:     async (data) => { /* ... */ },
    afterRemoveMember:      async (data) => { /* ... */ },
    beforeUpdateMemberRole: async (data) => { /* data.member, data.newRole, ... */ },
    afterUpdateMemberRole:  async (data) => { /* data.member, data.previousRole, ... */ },

    // Invitation lifecycle
    beforeCreateInvitation:  async (data) => { /* data.invitation, data.inviter, data.organization */ },
    afterCreateInvitation:   async (data) => { /* ... */ },
    beforeAcceptInvitation:  async (data) => { /* ... */ },
    afterAcceptInvitation:   async (data) => { /* data.invitation, data.member, data.user, data.organization */ },
    beforeRejectInvitation:  async (data) => { /* ... */ },
    afterRejectInvitation:   async (data) => { /* ... */ },
    beforeCancelInvitation:  async (data) => { /* ... */ },
    afterCancelInvitation:   async (data) => { /* ... */ },

    // Team lifecycle (when teams.enabled: true)
    beforeCreateTeam:      async (data) => { /* ... */ },
    afterCreateTeam:       async (data) => { /* ... */ },
    beforeUpdateTeam:      async (data) => { /* ... */ },
    afterUpdateTeam:       async (data) => { /* ... */ },
    beforeDeleteTeam:      async (data) => { /* ... */ },
    afterDeleteTeam:       async (data) => { /* ... */ },
    beforeAddTeamMember:   async (data) => { /* ... */ },
    afterAddTeamMember:    async (data) => { /* ... */ },
    beforeRemoveTeamMember: async (data) => { /* ... */ },
    afterRemoveTeamMember:  async (data) => { /* ... */ },
  },
})
```

The `before*` hooks can return `{ data: Record<string, any> }` to override the data being written. They can also throw `new APIError(...)` to abort the operation.

**Summary**: To auto-create an org on user signup, use `databaseHooks.user.create.after` on the main `betterAuth()` config, NOT the plugin's `organizationHooks` (which only fire for org-specific API calls).

---

### 4. `activeOrganizationId` on the Session Table

The plugin adds an optional `activeOrganizationId` column to the `session` table:

```javascript
// From lines 6082-6097
schema: {
  session: {
    fields: {
      activeOrganizationId: {
        type: "string",
        required: false,
        fieldName: options?.schema?.session?.fields?.activeOrganizationId
        // ^ allows remapping the DB column name, e.g. "active_organization_id"
      },
      // Only if teams.enabled:
      activeTeamId: {
        type: "string",
        required: false,
        fieldName: options?.schema?.session?.fields?.activeTeamId
      }
    }
  }
}
```

The runtime session object returned from `getSession` includes these:

```typescript
session: packages_core_dist_db.Session & {
  activeTeamId?: string;
  activeOrganizationId?: string;
};
```

The `activeOrganizationId` is set via the `setActiveOrganization` API endpoint, which updates the session row:

```javascript
// From line 346
const session = await context.internalAdapter.updateSession(
  sessionToken,
  { activeOrganizationId: organizationId },
  ctx
);
```

This means `activeOrganizationId` tracks which organization the user is currently "working in" for a given session, and many organization endpoints fall back to `session.session.activeOrganizationId` when no explicit `organizationId` is provided in the request body.

---

### 5. Configuration Options Summary

From the `OrganizationOptions` interface at lines 23-754 of `/Users/marc/.bun/install/cache/better-auth@1.3.27@@@1/dist/plugins/organization/index.d.ts`:

| Option | Type | Default | Description |
|--------|------|---------|-------------|
| `allowUserToCreateOrganization` | `boolean \| ((user: User) => boolean \| Promise<boolean>)` | `true` | Whether users can create orgs. Can be a function for dynamic checks (e.g., check subscription plan). |
| `organizationLimit` | `number \| ((user: User) => boolean \| Promise<boolean>)` | -- | Max orgs a user can create. |
| `creatorRole` | `string` | `"owner"` | Role assigned to the user who creates the org. |
| `membershipLimit` | `number` | `100` | Max members per organization. |
| `invitationExpiresIn` | `number` | 48 hours (ms) | Invitation link TTL. |
| `invitationLimit` | `number \| ((data, ctx) => number \| Promise<number>)` | `100` | Max pending invitations per org. |
| `cancelPendingInvitationsOnReInvite` | `boolean` | `false` | Auto-cancel old invites when re-inviting same email. |
| `requireEmailVerificationOnInvitation` | `boolean` | `false` | Require email verification before accepting/rejecting. |
| `sendInvitationEmail` | `(data, request?) => Promise<void>` | -- | Callback to send invitation emails. |
| `disableOrganizationDeletion` | `boolean` | `false` | Prevent org deletion entirely. |
| `ac` | `AccessControl` | `defaultAc` | Custom access control definition. |
| `roles` | `{ [key: string]: Role }` | `{ admin, owner, member }` | Role definitions with permissions. |
| `dynamicAccessControl` | `{ enabled?, maximumRolesPerOrganization? }` | disabled | Enable per-org custom roles stored in the DB. |
| `teams` | `{ enabled, defaultTeam?, maximumTeams?, maximumMembersPerTeam?, allowRemovingAllTeams? }` | disabled | Team sub-grouping within organizations. |
| `schema` | `{ session?, organization?, member?, invitation?, team?, teamMember?, organizationRole? }` | -- | Remap model names and field names. Add `additionalFields` to any table. |
| `organizationHooks` | (see section 3B above) | -- | Lifecycle hooks for all org operations. |

#### Default Roles and Permissions

From `/Users/marc/.bun/install/cache/better-auth@1.3.27@@@1/dist/plugins/organization/access/index.mjs`:

```
Default statements (available permission actions):
  organization: ["update", "delete"]
  member:       ["create", "update", "delete"]
  invitation:   ["create", "cancel"]
  team:         ["create", "update", "delete"]
  ac:           ["create", "read", "update", "delete"]

owner role:
  organization: ["update", "delete"]  -- can update AND delete
  member:       ["create", "update", "delete"]
  invitation:   ["create", "cancel"]
  team:         ["create", "update", "delete"]
  ac:           ["create", "read", "update", "delete"]

admin role:
  organization: ["update"]  -- can update but NOT delete
  member:       ["create", "update", "delete"]
  invitation:   ["create", "cancel"]
  team:         ["create", "update", "delete"]
  ac:           ["create", "read", "update", "delete"]

member role:
  organization: []
  member:       []
  invitation:   []
  team:         []
  ac:           ["read"]  -- can only read roles
```

---

### Relevance to the Rudel Codebase

Currently in Rudel (`/Users/marc/conductor/workspaces/rudel/wellington/apps/api/src/router.ts:27`), the `organizationId` is set to `context.user.id`. This means each user effectively IS their own "organization." To adopt the organization plugin properly, you would:

1. Add `organization()` to the plugins array in `/Users/marc/conductor/workspaces/rudel/wellington/apps/api/src/auth.ts`
2. Add the organization, member, and invitation tables to the Drizzle schema in `/Users/marc/conductor/workspaces/rudel/wellington/packages/sql-schema/`
3. Use `databaseHooks.user.create.after` to auto-create an org per user on signup
4. Switch the ingest router from `organizationId: context.user.id` to reading the `activeOrganizationId` from the session (or the user's membership)

