import { eq } from "drizzle-orm";
import { drizzle } from "drizzle-orm/postgres-js";
import postgres from "postgres";
import {
	member,
	organization,
	session,
	user,
} from "@rudel/sql-schema";

const connectionString = process.env.PG_CONNECTION_STRING;
if (!connectionString) {
	throw new Error("PG_CONNECTION_STRING environment variable is required");
}

const sql = postgres(connectionString, { max: 1 });
const db = drizzle(sql);

const users = await db.select().from(user);
console.log(`Found ${users.length} existing users`);

let created = 0;
let skipped = 0;

for (const u of users) {
	const existing = await db
		.select()
		.from(organization)
		.where(eq(organization.id, u.id))
		.limit(1);

	if (existing.length > 0) {
		console.log(`Skipping ${u.email} — org already exists`);
		skipped++;
		continue;
	}

	const slug = `${u.email.split("@")[0]}-${u.id.slice(0, 8)}`;

	await db.insert(organization).values({
		id: u.id,
		name: `${u.name}'s Workspace`,
		slug,
		createdAt: new Date(),
	});

	await db.insert(member).values({
		id: crypto.randomUUID(),
		organizationId: u.id,
		userId: u.id,
		role: "owner",
		createdAt: new Date(),
	});

	await db
		.update(session)
		.set({ activeOrganizationId: u.id })
		.where(eq(session.userId, u.id));

	console.log(`Created org for ${u.email} (${u.id})`);
	created++;
}

console.log(`Done. Created: ${created}, Skipped: ${skipped}`);

await sql.end();

